class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()
        self.longest_word_found = ""

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def find_longest_word(self) -> str:
        self.longest_word_found = ""

        def _dfs(node: TrieNode, current_word: str):
            if node.is_end_of_word:
                if len(current_word) > len(self.longest_word_found):
                    self.longest_word_found = current_word

            for char in sorted(node.children.keys()):
                child_node = node.children[char]
                _dfs(child_node, current_word + char)

        _dfs(self.root, "")
        return self.longest_word_found

